import hashlib
import time
import os
from functools import wraps

def cache_with_expiration(expiration_seconds=3600):
    """Decorator to cache function results with expiration and email anonymization."""
    _cache = {}

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = _generate_cache_key(func, args, kwargs)

            if cache_key in _cache:
                cached_result, timestamp = _cache[cache_key]
                if (time.time() - timestamp) < expiration_seconds:
                    return cached_result

            result = func(*args, **kwargs)
            anonymized_result = _anonymize_emails(result)
            _cache[cache_key] = (anonymized_result, time.time())

            return anonymized_result

        return wrapper

    return decorator

def _generate_cache_key(func, args, kwargs):
    """Generate a unique cache key."""
    return f"{func.__name__}-{str(args)}-{str(kwargs)}"

def _anonymize_emails(data):
    """Anonymize email addresses in the data."""
    if isinstance(data, str) and '@' in data:
        return _hash_email(data)
    elif isinstance(data, dict):
        return {k: _anonymize_emails(v) for k, v in data.items()}
    elif isinstance(data, (list, tuple, set)):
        return type(data)(_anonymize_emails(v) for v in data)
    return data

def _hash_email(email):
    """Hash the email address using SHA-256 and a salt."""
    salt = os.urandom(32)
    hashed = hashlib.sha256(salt + email.encode()).hexdigest()
    return f"anon-{hashed}"
