from confluent_kafka import Producer, Consumer, KafkaError
import uuid

class KafkaPubSub:
    def __init__(self, brokers="localhost:9092"):
        self.brokers = brokers

        # Create Producer
        self.producer = Producer({'bootstrap.servers': self.brokers})

        # Create Consumer
        self.consumer = Consumer({
            'bootstrap.servers': self.brokers,
            'group.id': str(uuid.uuid4()),
            'auto.offset.reset': 'earliest'
        })

    def publish_message(self, topic, message):
        def delivery_callback(err, msg):
            if err:
                print(f"Message delivery failed: {err}")
            else:
                print(f"Message delivered to {msg.topic()} [{msg.partition()}]")

        self.producer.produce(topic, message.encode('utf-8'), callback=delivery_callback)
        self.producer.poll(0)
        self.producer.flush()

    def subscribe_topic(self, topic):
        self.consumer.subscribe([topic])

    def consume_message(self):
        while True:
            message = self.consumer.poll(timeout=1.0)
            if message is None:
                continue
            if message.error():
                if message.error().code() == KafkaError._PARTITION_EOF:
                    continue
                else:
                    print(f"Error occurred: {message.error().str()}")
                    break
            yield message.value().decode('utf-8')

    def close(self):
        self.consumer.close()

# Usage Example:

# Instantiate PubSub System
kafka_system = KafkaPubSub()

# Subscribe to a topic
kafka_system.subscribe_topic('test_topic')

# Publish a message
kafka_system.publish_message('test_topic', 'Hello Kafka!')

# Consume message
for message in kafka_system.consume_message():
    print(f"Received message: {message}")
    break  # Example is only consuming one message for demonstration

# Close connection
kafka_system.close()
