# Product model
class Product:
    def __init__(self, name: str, price: float, id: Optional[int] = None):
        self.id = id
        self.name = name
        self.price = price

# Order model
class Order:
    def __init__(self, product_id: int, quantity: int, id: Optional[int] = None):
        self.id = id
        self.product_id = product_id
        self.quantity = quantity

# Define repository interfaces
class ProductRepository(ABC):
    @abstractmethod
    def get_product_by_id(self, product_id: int) -> Optional[Product]:
        pass

    @abstractmethod
    def save_product(self, product: Product):
        pass

    @abstractmethod
    def update_product(self, product_id: int, product_details: Dict[str, str]):
        pass

    @abstractmethod
    def delete_product(self, product_id: int):
        pass

class OrderRepository(ABC):
    @abstractmethod
    def get_order_by_id(self, order_id: int) -> Optional[Order]:
        pass

    @abstractmethod
    def save_order(self, order: Order):
        pass

# Implement repository interfaces with SQL data access
