	rateLimit  *rate.Limiter
	wg         sync.WaitGroup
	stopChan   chan struct{}
}

func NewConsumer(amqpURL, queueName string, workers int, rateLimit float64) (*Consumer, error) {
	conn, err := amqp.Dial(amqpURL)
	if err != nil {
		return nil, fmt.Errorf("dial: %s", err)
	}

	consumer := &Consumer{
		conn:      conn,
		queue:     queueName,
		workers:   workers,
		rateLimit: rate.NewLimiter(rate.Limit(rateLimit), 1),
		stopChan:  make(chan struct{}),
	}
	return consumer, nil
}

func (c *Consumer) processMessage(msg []byte) {
	fmt.Printf("Processing message: %s\n", msg)
	time.Sleep(100 * time.Millisecond) // simulate processing time
}

func (c *Consumer) handleDelivery(deliveries <-chan amqp.Delivery, id int) {
	defer c.wg.Done()
	for {
		select {
		case d, ok := <-deliveries:
			if !ok {
				return
			}
			if err := c.rateLimit.Wait(context.Background()); err != nil {
				log.Println("Rate limiter error:", err)
				continue
			}
			log.Printf("worker %d received message: %s\n", id, d.Body)
			c.processMessage(d.Body)
			err := d.Ack(false)
			if err != nil {
				log.Printf("worker %d error acknowledging message: %s, error: %v", id, d.Body, err)
			}

		case <-c.stopChan:
			return
		}
	}
}

func (c *Consumer) Consume() {
	ch, err := c.conn.Channel()
	if err != nil {
		log.Fatalf("channel: %s", err)
	}

	deliveries, err := ch.Consume(
		c.queue, // queue
		"",      // consumer
		false,   // auto-ack
		false,   // exclusive
		false,   // no-local
		false,   // no-wait
		nil,     // args
	)
	if err != nil {
		log.Fatalf("queue consume: %s", err)
	}

	for i := 0; i < c.workers; i++ {
		c.wg.Add(1)
		go c.handleDelivery(deliveries, i)
	}
}

func (c *Consumer) Stop() {
	close(c.stopChan)
	c.wg.Wait()
	c.conn.Close()
}

