  const [data, setData] = useState({});
  const [errors, setErrors] = useState<Ajv.ErrorObject[] | null>(null);
  const [history, setHistory] = useState<JSONSchema7[]>([]);
  const [future, setFuture] = useState<JSONSchema7[]>([]);

  const validate = () => {
    const validate = ajv.compile(schema);
    const valid = validate(data);
    setErrors(valid ? null : validate.errors);
  };

  const undo = useCallback(() => {
