// Transcode performs transcoding using FFmpeg with CUDA acceleration
func Transcode(ctx context.Context, input, output string) error {
	cmd := exec.CommandContext(ctx, "ffmpeg",
		"-hwaccel", "cuda",
		"-i", input,
		"-c:v", "h264_nvenc",
		"-b:v", "2M",
		"-s", "1280x720",
		"-f", "mp4",
		"-y", output,
	)
	var stderr bytes.Buffer
	cmd.Stderr = &stderr
	if err := cmd.Run(); err != nil {
		return fmt.Errorf("ffmpeg error: %v, details: %s", err, stderr.String())
	}
	return nil
}

// Start initializes the worker to process jobs
func (w *Worker) Start(ctx context.Context) {
	defer w.wg.Done()
	for job := range w.jobQueue {
		if err := Transcode(ctx, job.input, job.output); err != nil {
